using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpStdioServer;

[McpServerToolType]
public static class ApiLookupTool
{
    [McpServerTool, Description("Fetches data from an external API by path and returns the JSON response.")]
    public static async Task<string> FetchApiData(
        IHttpClientFactory httpClientFactory,
        [Description("The API URL to fetch data from (e.g. https://api.example.com/data)")] string url,
        CancellationToken cancellationToken = default)
    {
        using var client = httpClientFactory.CreateClient("ApiClient");

        var response = await client.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpStdioServer;

[McpServerPromptType]
public static class SummarizePrompt
{
    [McpServerPrompt, Description("Generates a prompt that asks the model to summarize the provided text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text to summarize")] string text,
        [Description("Optional maximum length hint (e.g. '2 sentences', '100 words')")] string? maxLength = null)
    {
        var instruction = maxLength is not null
            ? $"Summarize the following text in {maxLength}."
            : "Summarize the following text concisely.";

        return
        [
            new PromptMessage
            {
                Role = Role.User,
                Content = new Content { Type = "text", Text = $"{instruction}\n\n{text}" }
            }
        ];
    }
}

